114	static void* launch_combine(void* x,
115	                            void* topk_weights,
116	                            int* src_metadata,
117	                            int* psum_num_recv_tokens_per_scaleup_rank,
118	                            int* token_metadata_at_forward,
119	                            int* channel_linked_list,
120	                            const ncclDevComm_t& nccl_dev_comm, const ncclWindow_t& nccl_window,
121	                            void* buffer, void* workspace,
122	                            const int& num_reduced_tokens, const int& num_max_tokens_per_rank,
123	                            const int& hidden,
124	                            const int& num_experts, const int& num_topk,
125	                            const int& num_qps, const int64_t& num_timeout_cycles,
126	                            const int& num_scaleout_ranks, const int& num_scaleup_ranks,
127	                            const int& scaleout_rank_idx, const int& scaleup_rank_idx,
128	                            const bool& is_scaleup_nvlink,
129	                            const int& num_sms, const int& num_smem_bytes,
130	                            const int& num_channels,
131	                            const bool& use_expanded_layout, const bool& allow_multiple_reduction,
132	                            const at::cuda::CUDAStream& stream) {
133	    // Maximize shared memory utilization
134	    const auto token_layout = get_combine_token_layout(hidden, sizeof(nv_bfloat16), num_topk);
135	    auto num_warps = std::min(num_smem_bytes / token_layout.get_num_bytes<true>(), 32);
136	
137	    // Decide warps
138	    int num_scaleup_warps = 0, num_forward_warps = 0;
139	    if (num_scaleout_ranks > 1) {
140	        EP_HOST_ASSERT(num_channels % num_sms == 0 and
141	                       "Invalid number of channels or SMs, you may use a different SM count than dispatch");
142	        EP_HOST_ASSERT(num_channels / num_sms <= 16);
143	
144	        num_scaleup_warps = num_forward_warps = num_channels / num_sms;
145	        num_warps = num_scaleup_warps + num_forward_warps;
146	        EP_HOST_ASSERT(num_warps * token_layout.get_num_bytes<true>() <= num_smem_bytes and
147	                       "Invalid combine SM count, please try to match your dispatch config");
148	    }
149	
150	    // Generate, build and launch
151	    const auto num_threads = num_warps * 32;
152	    const CombineRuntime::Args args = {
153	        .is_scaleup_nvlink = is_scaleup_nvlink,
154	        .use_expanded_layout = use_expanded_layout,
155	        .allow_multiple_reduction = allow_multiple_reduction,
156	        .num_scaleup_warps = num_scaleup_warps, .num_forward_warps = num_forward_warps,
157	        .num_scaleout_ranks = num_scaleout_ranks, .num_scaleup_ranks = num_scaleup_ranks,
158	        .hidden = hidden,
159	        .num_max_tokens_per_rank = num_max_tokens_per_rank,
160	        .num_experts = num_experts,
161	        .num_topk = num_topk,
162	        .num_qps = num_qps, .num_timeout_cycles = num_timeout_cycles,
163	        .x = static_cast<nv_bfloat16*>(x),
164	        .topk_weights = static_cast<float*>(topk_weights),
165	        .src_metadata = src_metadata,
166	        .psum_num_recv_tokens_per_scaleup_rank = psum_num_recv_tokens_per_scaleup_rank,
167	        .token_metadata_at_forward = token_metadata_at_forward,
168	        .channel_linked_list = channel_linked_list,
169	        .nccl_dev_comm = nccl_dev_comm, .nccl_window = nccl_window,
170	        .buffer = buffer, .workspace = workspace,
171	        .scaleout_rank_idx = scaleout_rank_idx, .scaleup_rank_idx = scaleup_rank_idx,
172	        .num_reduced_tokens = num_reduced_tokens,
173	        // NOTES: make cluster dim 2 to overlap with clustered computation kernels
174	        .launch_args = jit::LaunchArgs(num_sms, num_threads, num_smem_bytes, 2 - (num_sms % 2), true)
175	    };
176	    const auto code = CombineRuntime::generate(args);
177	    const auto runtime = jit::compiler->build("combine", code);
178	    CombineRuntime::launch(runtime, args, stream);
179	
180	    // Return the buffer to be reduced
181	    if (num_scaleout_ranks == 1)
182	        return buffer;
183	
184	    // For hybrid mode, we have to skip the scale-up buffer
185	    const bool is_scaleup_buffer_rank_layout =
186	        allow_multiple_reduction ? (num_scaleup_ranks <= num_topk) : false;
187	    const auto scaleup_buffer = layout::BufferLayout<false>(
188	        token_layout, 
189	        is_scaleup_buffer_rank_layout ? num_scaleup_ranks : num_topk,
190	        num_scaleout_ranks * num_max_tokens_per_rank,
191	        buffer);
192	    return scaleup_buffer.get_buffer_end_ptr();
193	}
