222	using namespace deep_ep::elastic;
223	
224	static void __instantiate_kernel() {{
225	    auto ptr = reinterpret_cast<void*>(&combine_reduce_epilogue_impl<{}, {}, {}, {}, {}, {}, {}, {}, {}, {}>);
226	}}
227	)",                        args.use_expanded_layout, args.allow_multiple_reduction,
228	                           args.launch_args.grid_dim.first,
229	                           args.launch_args.num_threads / 32,
230	                           args.num_scaleout_ranks, args.num_scaleup_ranks,
231	                           args.hidden,
232	                           args.num_max_tokens_per_rank,
233	                           args.num_experts, args.num_topk);
234	    }
