20	          int kNumMaxTokensPerRank,
21	          int kNumExperts, int kNumTopk,
22	          int kNumQPs, int64_t kNumTimeoutCycles,
23	          int kNumThreads = kNumWarps * 32,
24	          int kNumHiddenBytes = kHidden * sizeof(nv_bfloat16),
25	          bool kUseRankLayout = use_rank_layout<kAllowMultipleReduction, kNumRanks, kNumTopk>(),
26	          int kNumTokensInLayout = get_num_tokens_in_layout<kAllowMultipleReduction, kNumRanks, kNumTopk>(),
27	          typename team_t = std::conditional_t<kIsScaleupNVLink, ncclTeamTagLsa, ncclTeamTagWorld>>
28	__global__ void __launch_bounds__(kNumThreads, 1)
29	combine_impl(nv_bfloat16* x,
30	             float* topk_weights,
31	             int* src_metadata, int* psum_num_recv_tokens_per_scaleup_rank,
32	             const ncclDevComm_t nccl_dev_comm, const ncclWindow_t nccl_window,
33	             void* buffer, void* workspace,
34	             const int rank_idx,
35	             int num_reduced_tokens) {
36	    // Utils
37	    const auto sm_idx = static_cast<int>(blockIdx.x);
38	    const auto thread_idx = static_cast<int>(threadIdx.x);
39	    const auto warp_idx = (ptx::get_warp_idx() + rank_idx) % kNumWarps;
40	    const auto lane_idx = ptx::get_lane_idx();
41	    const auto global_warp_idx = warp_idx * kNumSMs + sm_idx;
42	    constexpr bool kDoExpandedSend = not kAllowMultipleReduction and kUseExpandedLayout;
43	
44	    // We should assign the real number of received tokens if without CPU sync
45	    if (num_reduced_tokens == kNumMaxTokensPerRank * kNumRanks)
46	        num_reduced_tokens = __ldg(psum_num_recv_tokens_per_scaleup_rank + kNumRanks - 1);
