51	    const auto tma_buffer = layout::BufferLayout<true>(token_layout, kNumWarps, 1, smem)
52	        .get_rank_buffer(warp_idx).get_token_buffer(0);
53	    const auto recv_buffer = layout::BufferLayout<false>(
54	        token_layout, kNumTokensInLayout, kNumMaxTokensPerRank, buffer);
55	    const auto send_buffer = layout::BufferLayout<false>(
56	        token_layout, kNumRanks,
57	        kNumMaxTokensPerRank * (kDoExpandedSend ? kNumTopk : 1),
58	        recv_buffer.get_buffer_end_ptr());
59	
60	    // Init TMA
61	    ptx::arrival_phase phase = 0;
62	    const auto mbarrier_ptr = tma_buffer.get_mbarrier_ptr();
63	    if (ptx::elect_one_sync())
64	        ptx::mbarrier_init_with_fence(mbarrier_ptr, 1);
