66	
67	    // Expanding send mode must not be backward
68	    if constexpr (kDoExpandedSend)
69	        EP_DEVICE_ASSERT(topk_weights == nullptr);
70	
71	    // Gin handle
72	    // We treat each warp as a "channel"
73	    const auto [qp_idx, sharing_mode] = comm::get_qp_mode<kNumSMs, kNumQPs, kNumWarps>(sm_idx, warp_idx);
74	    const auto gin = handle::NCCLGin(nccl_dev_comm, nccl_window, qp_idx, sharing_mode);
75	
76	    // Full barrier to ensure the remote buffer is available
77	    const auto workspace_layout = layout::WorkspaceLayout(workspace, 1, kNumRanks, kNumExperts);
78	    comm::gpu_barrier<kIsScaleupNVLink, 1, kNumRanks,
79	                      kNumSMs, kNumThreads, kNumQPs, kNumTimeoutCycles, comm::kCombineTag0, false, false, true>(
80	        gin, workspace_layout, 0, rank_idx, sm_idx, thread_idx);
81	
82	    // Do TMA writes into the remote buffers
83	    int num_tokens_per_warp = math::ceil_div(num_reduced_tokens, kNumSMs * kNumWarps);
84	    const int token_start_idx = num_tokens_per_warp * global_warp_idx;
85	    const int token_end_idx = min(token_start_idx + num_tokens_per_warp, num_reduced_tokens);
86	    for (int i = token_start_idx; i < token_end_idx; ++ i) {
87	        // The master slot index during dispatch
88	        constexpr int kMetadataStride = 2 + kNumTopk;
89	        const int src_token_idx = __ldg(src_metadata + i * kMetadataStride) % kNumMaxTokensPerRank;
90	        const int src_rank_topk_idx = __ldg(src_metadata + i * kMetadataStride + 1);
91	        const int src_rank_idx = src_rank_topk_idx / kNumTopk;
92	        const int src_topk_idx = src_rank_topk_idx % kNumTopk;
93	
94	        // Directly to the remote or via RDMA
95	        const bool nvlink_bypass = gin.is_nvlink_accessible<team_t>(src_rank_idx);
96	        layout::TokenLayout master_token_buffer = [=]() {
97	            // NVLink bypass
98	            if (nvlink_bypass) {
99	                auto token_buffer = recv_buffer.get_rank_buffer(kUseRankLayout ? rank_idx : src_topk_idx).get_token_buffer(src_token_idx);
100	                token_buffer.set_base_ptr(gin.get_sym_ptr<team_t>(token_buffer.get_base_ptr(), src_rank_idx));
101	                return token_buffer;
102	            }
103	
104	            // Use RDMA
105	            return send_buffer.get_rank_buffer(src_rank_idx).get_token_buffer(src_token_idx);
106	        }();
107	
108	        // Hidden requirements
109	        EP_STATIC_ASSERT(kHidden % (32 * sizeof(int4) / sizeof(nv_bfloat16)) == 0, "Invalid hidden");
110	        using combine_vec_t = typename CombineVecTraits<kHidden * sizeof(nv_bfloat16)>::vec_t;
111	        constexpr int kHiddenVec = kHidden * sizeof(nv_bfloat16) / sizeof(combine_vec_t);
112	
113	        // Read source indices for expand mode
114	        int stored_topk_slot_idx = -1;
115	        if constexpr (kUseExpandedLayout) {
116	            if (lane_idx < kNumTopk)
117	                stored_topk_slot_idx = __ldg(src_metadata + i * kMetadataStride + (2 + lane_idx));
118	            __syncwarp();
119	        }
120	
121	        // 3 cases:
122	        //  - no expand + no reduce, or expand + no reduce
123	        //  - expand + reduce
124	        //  - expand + send all
125	        auto reduce_valid_mask = ptx::gather(stored_topk_slot_idx >= 0);
126	        auto no_local_reduce = not kUseExpandedLayout or (kAllowMultipleReduction and __popc(reduce_valid_mask) == 1);
127	        if (no_local_reduce) {
128	            int token_idx_in_tensor = i;
129	            if constexpr (kUseExpandedLayout)
130	                token_idx_in_tensor = ptx::exchange(stored_topk_slot_idx, ptx::get_master_lane_idx(reduce_valid_mask));
