146	            // Sort valid top-k indices to front
147	            int topk_slot_idx[kNumTopk];
148	            compute_topk_slots(
149	                topk_slot_idx, reduce_valid_mask,
150	                [=](const int& idx) {
151	                    return ptx::exchange(stored_topk_slot_idx, idx);
152	                }
153	            );
154	
155	            // Reduce into shared memory
156	            constexpr int kUnrollFactor = get_max_unroll_factor<kHiddenVec, 4>();
157	            combine_reduce<kHiddenVec, kUnrollFactor, math::constexpr_ceil_div(kNumTopk, kNumRanks)>(
158	                lane_idx, topk_slot_idx, static_cast<combine_vec_t*>(tma_buffer.get_base_ptr()),
159	                /* Get source base */ [=](const int& slot_idx) {
160	                    return math::advance_ptr<combine_vec_t>(
161	                        x, slot_idx * static_cast<int64_t>(kNumHiddenBytes));
162	                },
163	                /* Wait buffer release */ [=]() {
164	                    ptx::tma_store_wait();
165	                    __syncwarp();
166	                }
167	            );
168	            ptx::tma_store_fence();
169	            __syncwarp();
170	
171	            // Issue TMA stores
172	            if (ptx::elect_one_sync()) {
173	                ptx::tma_store_1d(master_token_buffer.get_base_ptr(), tma_buffer.get_base_ptr(), kNumHiddenBytes);
174	                ptx::tma_store_commit();
175	            }
176	            __syncwarp();
177	        } else {
178	            // No local reduction, send all data (expanded send)
179	            #pragma unroll
180	            for (int k = 0; k < kNumTopk; ++ k) {
181	                const auto slot_idx = ptx::exchange(stored_topk_slot_idx, k);
182	                if (slot_idx >= 0) {
183	                    const auto src_token_ptr = math::advance_ptr<int4>(x, slot_idx * static_cast<int64_t>(kNumHiddenBytes));
184	                    const auto token_buffer = recv_buffer.get_rank_buffer(k).get_token_buffer(src_token_idx);
185	                    if (ptx::elect_one_sync()) {
186	                        // Load
187	                        ptx::tma_store_wait();
188	                        ptx::tma_load_1d(tma_buffer.get_base_ptr(), src_token_ptr, mbarrier_ptr, kNumHiddenBytes);
189	                        ptx::mbarrier_arrive_and_set_tx(mbarrier_ptr, kNumHiddenBytes);
190	                        ptx::mbarrier_wait_and_flip_phase(mbarrier_ptr, phase);
191	
192	                        if (nvlink_bypass) {
193	                            // Write into the same position
194	                            ptx::tma_store_1d(gin.get_sym_ptr<team_t>(token_buffer.get_base_ptr(), src_rank_idx),
195	                                              tma_buffer.get_base_ptr(), kNumHiddenBytes);
196	                            ptx::tma_store_commit();
197	                        } else {
198	                            // Write to the RDMA send buffer
199	                            const auto send_token_buffer =
200	                                send_buffer.get_rank_buffer(src_rank_idx).get_token_buffer(src_token_idx * kNumTopk + k);
201	                            ptx::tma_store_1d(send_token_buffer.get_base_ptr(), tma_buffer.get_base_ptr(), kNumHiddenBytes);
202	                            ptx::tma_store_commit();
203	                            ptx::tma_store_wait();
204	
205	                            // Issue RDMA
206	                            gin.put<team_t>(token_buffer.get_base_ptr(), send_token_buffer.get_base_ptr(),
207	                                            kNumHiddenBytes, src_rank_idx);
208	                        }
209	                    }
210	                    __syncwarp();
211	                }
212	            }
213	        }
214	
215	        // Write topk weights
216	        if (not kDoExpandedSend and topk_weights != nullptr and lane_idx < kNumTopk) {
217	            float value = 0;
218	            if constexpr (kUseExpandedLayout) {
219	                if (stored_topk_slot_idx >= 0)
220	                    value = __ldg(topk_weights + stored_topk_slot_idx);
221	            } else {
222	                value = __ldg(topk_weights + (i * kNumTopk + lane_idx));
223	            }
224	            master_token_buffer.get_topk_weights_ptr()[lane_idx] = value;
225	        }
226	        __syncwarp();
227	
228	        // Wait send buffer's TMA store and issue RDMA send
229	        // NOTES: `kDoExpandedSend` mode has already issued
230	        if (not kDoExpandedSend and not nvlink_bypass and ptx::elect_one_sync()) {
231	            ptx::tma_store_wait();
232	            const auto dst_ptr = recv_buffer.get_rank_buffer(kUseRankLayout ? rank_idx : src_topk_idx)
233	                .get_token_buffer(src_token_idx).get_base_ptr();
234	            gin.put<team_t>(dst_ptr, master_token_buffer.get_base_ptr(),
235	                            master_token_buffer.get_num_bytes<false>(), src_rank_idx);
236	        }
237	    }
238	
239	    // Final barrier to ensure data arrival
240	    comm::gpu_barrier<kIsScaleupNVLink, 1, kNumRanks,
241	                      kNumSMs, kNumThreads, kNumQPs, kNumTimeoutCycles, comm::kCombineTag1, true, true, false>(
242	        gin, workspace_layout, 0, rank_idx, sm_idx, thread_idx);
243	}
