3	#include <deep_ep/common/comm.cuh>
4	#include <deep_ep/common/layout.cuh>
5	#include <deep_ep/common/math.cuh>
6	#include <deep_ep/common/ptx.cuh>
7	#include <deep_ep/impls/combine_utils.cuh>
8	
9	namespace deep_ep::elastic {
10	
11	template <bool kUseExpandedLayout, bool kAllowMultipleReduction,
12	          int kNumSMs,
13	          int kNumScaleupWarps, int kNumForwardWarps,
14	          int kNumScaleoutRanks, int kNumScaleupRanks,
15	          int kHidden,
16	          int kNumMaxTokensPerRank,
17	          int kNumExperts, int kNumTopk,
18	          int kNumQPs, int64_t kNumTimeoutCycles,
19	          int kNumScaleupRanksPerLane = math::constexpr_ceil_div(kNumScaleupRanks, 32),
20	          int kNumScaleupUpdateInterval = 3,
21	          int kNumChannelsPerSM = kNumForwardWarps,
22	          int kNumChannels = kNumChannelsPerSM * kNumSMs,
23	          int kNumMaxTokensPerChannel = math::constexpr_ceil_div(kNumMaxTokensPerRank, kNumChannels),
24	          int kNumRanks = kNumScaleoutRanks * kNumScaleupRanks,
25	          int kNumWarps = kNumScaleupWarps + kNumForwardWarps,
26	          int kNumThreads = kNumWarps * 32,
27	          int kNumHiddenBytes = kHidden * sizeof(nv_bfloat16),
28	          bool kUseScaleoutRankLayout = use_rank_layout<kAllowMultipleReduction, kNumScaleoutRanks, kNumTopk>(),
29	          bool kUseScaleupRankLayout = use_rank_layout<kAllowMultipleReduction, kNumScaleupRanks, kNumTopk>(),
30	          int kNumTokensInScaleoutLayout = get_num_tokens_in_layout<kAllowMultipleReduction, kNumScaleoutRanks, kNumTopk>(),
31	          int kNumTokensInScaleupLayout = get_num_tokens_in_layout<kAllowMultipleReduction, kNumScaleupRanks, kNumTopk>()>
32	__global__ void __launch_bounds__(kNumThreads, 1)
33	hybrid_combine_impl(nv_bfloat16* x,
34	                    float* topk_weights,
35	                    int* src_metadata,
36	                    int* psum_num_recv_tokens_per_scaleup_rank,
37	                    int* token_metadata_at_forward,
38	                    int* channel_linked_list,
39	                    const ncclDevComm_t nccl_dev_comm, const ncclWindow_t nccl_window,
40	                    void* buffer, void* workspace,
41	                    const int scaleout_rank_idx, const int scaleup_rank_idx,
42	                    int num_reduced_tokens) {
43	    // Utils
44	    const auto sm_idx = static_cast<int>(blockIdx.x);
45	    const auto thread_idx = static_cast<int>(threadIdx.x);
46	    const auto warp_idx = ptx::get_warp_idx();
47	    const auto lane_idx = ptx::get_lane_idx();
48	    constexpr bool kDoExpandedSend = not kAllowMultipleReduction and kUseExpandedLayout;
49	
50	    // Combine vector type selection
51	    using combine_vec_t = typename CombineVecTraits<kNumHiddenBytes>::vec_t;
52	    constexpr int kHiddenVec = kNumHiddenBytes / sizeof(combine_vec_t);
53	
54	    // Workspaces
55	    const auto workspace_layout = layout::WorkspaceLayout(workspace, kNumScaleoutRanks, kNumScaleupRanks, kNumExperts);
56	
57	    // We should assign the real number of received tokens if without CPU sync
58	    if (num_reduced_tokens == kNumMaxTokensPerRank * kNumRanks)
59	        num_reduced_tokens = __ldg(psum_num_recv_tokens_per_scaleup_rank + kNumScaleupRanks - 1);
60	
61	    // Token layouts
62	    const auto token_layout = layout::TokenLayout(kNumHiddenBytes, 0, kNumTopk, false);
63	
64	    // TMA buffers
65	    extern __shared__ __align__(ptx::kNumTMAAlignBytes) int8_t smem[];
66	    const auto tma_buffer = layout::BufferLayout<true>(
67	        token_layout, kNumWarps, 1, smem).get_rank_buffer(warp_idx).get_token_buffer(0);
68	
69	    // All the buffer layouts
70	    auto scaleup_buffer = layout::BufferLayout<false>(
71	        token_layout, kNumTokensInScaleupLayout, kNumScaleoutRanks * kNumMaxTokensPerRank,
72	        buffer);
73	    auto scaleout_recv_buffer = layout::BufferLayout<false>(
74	        token_layout, kNumTokensInScaleoutLayout, kNumMaxTokensPerRank,
75	        scaleup_buffer.get_buffer_end_ptr());
76	    auto scaleout_send_buffer = layout::BufferLayout<false>(
