512	                int topk_slot_idx[kNumTokensInScaleupLayout];
513	                compute_topk_slots(
514	                    topk_slot_idx, reduce_valid_mask,
515	                    [=](const int& idx) {
516	                        return ptx::exchange(stored_src_buffer_idx, idx);
517	                    }
518	                );
519	
520	                // Do reduce
521	                constexpr int kUnrollFactor = get_max_unroll_factor<kHiddenVec, kAdjustRegisters ? 8 : 4>();
522	                combine_reduce<kHiddenVec, kUnrollFactor, math::constexpr_ceil_div(kNumTopk, kNumScaleoutRanks)>(
523	                    lane_idx, topk_slot_idx, static_cast<combine_vec_t*>(tma_buffer.get_base_ptr()),
524	                    /* Get source base */ [=](const int& slot_idx) {
525	                        return static_cast<combine_vec_t*>(scaleup_buffer.get_token_buffer(slot_idx, true).get_base_ptr());
526	                    },
527	                    /* Wait buffer release */ [=]() {
528	                        flush_last_tma_and_issue_rdma();
529	                    }
530	                );
531	
532	                // Merge topk weights
533	                // NOTES: the slot indices must follow the master lane
534	                stored_src_buffer_idx = ptx::exchange(
535	                    stored_src_buffer_idx, ptx::get_master_lane_idx(ptx::match(stored_src_scaleup_rank_idx)));
536	                if (stored_src_scaleup_rank_idx >= 0) {
537	                    tma_buffer.get_topk_weights_ptr()[lane_idx] =
538	                        scaleup_buffer.get_token_buffer(stored_src_buffer_idx, true)
539	                                    .get_topk_weights_ptr()[lane_idx];
540	                }
541	                ptx::tma_store_fence();
542	                __syncwarp(); // Necessary to let the leader lane see the writes
543	
544	                // Assign send and receive buffers
545	                // NOTES: as we only have 1 destination, we will use "send" as "recv" for local transfer
546	                int scaleout_recv_buffer_rank_idx;
547	                if constexpr (kUseScaleoutRankLayout) {
548	                    scaleout_recv_buffer_rank_idx = scaleout_rank_idx;
549	                } else {
550	                    const int src_topk_idx = ptx::get_master_lane_idx(ptx::gather(stored_src_scaleup_rank_idx >= 0));
551	                    scaleout_recv_buffer_rank_idx = src_topk_idx;
552	                }
553	                const auto recv_token_buffer = scaleout_recv_buffer.get_rank_buffer(scaleout_recv_buffer_rank_idx).get_token_buffer(src_token_idx);
554	                const auto send_token_buffer = src_scaleout_rank_idx == scaleout_rank_idx ?
555	                    recv_token_buffer :
556	                    scaleout_send_buffer.get_token_buffer(i);
557	
558	                // Write into scale-out send buffer or local rank recv buffer bypass
559	                if (ptx::elect_one_sync()) {
560	                    ptx::tma_store_1d(send_token_buffer.get_base_ptr(), tma_buffer.get_base_ptr(),
561	                                    token_layout.get_num_bytes<false>());
562	                    ptx::tma_store_commit();
563	                }
564	                __syncwarp();
565	
566	                // Record RDMA info to issue later
567	                last_src_scaleout_rank_idx = src_scaleout_rank_idx;
568	                last_is_token_last_in_chunk = is_token_last_in_chunk;
569	                last_recv_token_buffer_ptr = recv_token_buffer.get_base_ptr();
570	                last_send_token_buffer_ptr = send_token_buffer.get_base_ptr();
571	            }
572	        }
573	
574	        // Issue the last RDMA
575	        if constexpr (kAllowMultipleReduction)
576	            flush_last_tma_and_issue_rdma();
577	
578	        // Clean scaleup tails
579	        #pragma unroll
580	        for (int j = 0; j < kNumScaleupRanksPerLane; ++ j) {
581	            const auto k = j * 32 + lane_idx;
582	            if (j < (kNumScaleupRanksPerLane - 1) or k < kNumScaleupRanks)
583	                *workspace_layout.get_channel_scaleup_tail_ptr(channel_idx, k) = 0;
584	        }
585	        __syncwarp();
586	
587	        // Update, wait and clean
588	        EP_STATIC_ASSERT(kNumScaleoutRanks <= 32, "Invalid ranks");
589	        const auto expected_signal = math::pack2<int, int64_t>(1, 0);
590	        gin.flush<ncclCoopWarp>();
591	        if (lane_idx < kNumScaleoutRanks) {
592	            // Update remote tails
593	            gin.red_add_rel<ncclTeamTagRail>(
594	                workspace_layout.get_scaleout_channel_signaled_tail_ptr(channel_idx, scaleout_rank_idx),
595	                expected_signal, lane_idx);
596	        }
597	        __syncwarp();
598	
599	        // Wait tail arrival
600	        if (lane_idx < kNumScaleoutRanks) {
601	            const auto wait_ptr = workspace_layout.get_scaleout_channel_signaled_tail_ptr(channel_idx, lane_idx);
602	            comm::timeout_while<kNumTimeoutCycles>([=](const bool& is_last_check) {
603	                const auto signal = ptx::ld_acquire_sys<int64_t>(wait_ptr);
604	                if (signal == expected_signal) {
605	                    // Clean for next usages
606	                    *wait_ptr = 0;
607	                    return true;
608	                }
609	
610	                if (is_last_check) {
611	                    printf("DeepEP combine (scale-out wait all) timeout, scale-out: %d/%d, scale-up: %d/%d, "
612	                           "channel: %d, lane: %d, signal: %lld, expected: %lld\n",
613	                           scaleout_rank_idx, kNumScaleoutRanks, scaleup_rank_idx, kNumScaleupRanks,
614	                           channel_idx, lane_idx,
615	                           signal, expected_signal);
616	                }
617	                return false;
618	            });
619	        }
620	        __syncwarp();
621	    }
622	
623	    // No barrier at epilogue
624	}
625	
626	}  // namespace deep_ep::elastic
